changeSet.sql:
UPDATE orders SET item_type = NULL WHERE item_type IS NOT NULL AND TRIM(item_type) = '';
UPDATE orders SET item_type = 'PREMIUM' WHERE item_type IS NOT NULL AND LOWER(TRIM(item_type)) IN ('premium');
UPDATE orders SET item_type = 'STANDARD' WHERE item_type IS NOT NULL AND LOWER(TRIM(item_type)) IN ('standard', 'standart');
UPDATE orders SET item_type = 'CUSTOM' WHERE item_type IS NOT NULL AND item_type NOT IN ('PREMIUM', 'STANDARD', 'CUSTOM');
